SELECT mission_id
FROM missions
ORDER BY launch_date;

SELECT COUNT(*) AS active_launch_site_count
FROM launch_sites
WHERE site_status = 'active';

SELECT vehicle_name
FROM launch_vehicles
WHERE vehicle_status = 'retired';

SELECT mission_id
FROM missions
ORDER BY mission_cost DESC;

SELECT vehicle_name
FROM launch_vehicles
WHERE vehicle_id = 1;
